import { v4 as uuidv4 } from 'uuid';

import { getBackendConfig, getWebhookUrl, updateWebhookUrl } from '$lib/apis';
	import {
		getAdminConfig,
		getLdapConfig,
		getLdapServer,
		updateAdminConfig,
		updateLdapConfig,
		updateLdapServer
	} from '$lib/apis/auths';
	import { getBanners, setBanners } from '$lib/apis/configs';
	import { getGroups } from '$lib/apis/groups';
	import SensitiveInput from '$lib/components/common/SensitiveInput.svelte';
	import Switch from '$lib/components/common/Switch.svelte';
	import Tooltip from '$lib/components/common/Tooltip.svelte';
import { banners as _banners, config } from '$lib/stores';
import type { Banner } from '$lib/types';
import { onMount, getContext } from 'svelte';
	import { toast } from 'svelte-sonner';
	import Textarea from '$lib/components/common/Textarea.svelte';
	import Banners from './Interface/Banners.svelte';

	const i18n = getContext('i18n');
	const FORK_INFO = (
		import.meta.env.VITE_GPTHUB_FORK_INFO ??
		'Base OpenWebUI v0.8.12 | Fork by kreepery2004 team for MTC TrueTechHack 2026 | Maintainers: Andrey Rastopshin & Dmitrii Malofeev'
	).trim();
	const FORK_INFO_LINES = FORK_INFO.split('|').map((line) => line.trim()).filter(Boolean);
	const splitParenthetical = (line: string) => {
		return line
			.split(/(\([^)]*\))/g)
			.filter(Boolean)
			.map((part) => ({ text: part, isParen: /^\([^)]*\)$/.test(part) }));
	};

	export let saveHandler: Function;

	let adminConfig = null;
	let webhookUrl = '';
	let groups = [];

	let banners: Banner[] = [];

	// LDAP
	let ENABLE_LDAP = false;
	let LDAP_SERVER = {
		label: '',
		host: '',
		port: '',
		attribute_for_mail: 'mail',
		attribute_for_username: 'uid',
		app_dn: '',
		app_dn_password: '',
		search_base: '',
		search_filters: '',
		use_tls: false,
		certificate_path: '',
		ciphers: ''
	};

	const tip = (text: string) => {
		return `<div style="max-width: 320px; white-space: normal; text-align: left;">${text}</div>`;
	};

	const updateLdapServerHandler = async () => {
		if (!ENABLE_LDAP) return;
		const res = await updateLdapServer(localStorage.token, LDAP_SERVER).catch((error) => {
			toast.error(`${error}`);
			return null;
		});
		if (res) {
			toast.success($i18n.t('LDAP server updated'));
		}
	};

	const updateBanners = async () => {
		_banners.set(await setBanners(localStorage.token, banners));
	};

	const updateHandler = async () => {
		webhookUrl = await updateWebhookUrl(localStorage.token, webhookUrl);
		const res = await updateAdminConfig(localStorage.token, adminConfig);
		await updateLdapConfig(localStorage.token, ENABLE_LDAP);
		await updateLdapServerHandler();

		await updateBanners();

		await config.set(await getBackendConfig());

		if (res) {
			saveHandler();
		} else {
			toast.error($i18n.t('Failed to update settings'));
		}
	};

	onMount(async () => {
		await Promise.all([
			(async () => {
				adminConfig = await getAdminConfig(localStorage.token);
			})(),

			(async () => {
				webhookUrl = await getWebhookUrl(localStorage.token);
			})(),
			(async () => {
				LDAP_SERVER = await getLdapServer(localStorage.token);
			})(),
			(async () => {
				groups = await getGroups(localStorage.token);
			})()
		]);

		const ldapConfig = await getLdapConfig(localStorage.token);
		ENABLE_LDAP = ldapConfig.ENABLE_LDAP;

		banners = await getBanners(localStorage.token);
	});

</script>

